package com.museumheist.game.input;import org.junit.Test;import static org.junit.Assert.*;public class TouchCommandQueueTest{@Test public void order(){TouchCommandQueue q=new TouchCommandQueue(16);TouchCommandQueue.Command c=new TouchCommandQueue.Command();q.offer(1,2,10,20);q.offer(2,2,15,25);assertTrue(q.poll(c));assertEquals(1,c.getType());assertTrue(q.poll(c));assertEquals(2,c.getType());}@Test public void values(){TouchCommandQueue q=new TouchCommandQueue(16);TouchCommandQueue.Command c=new TouchCommandQueue.Command();q.offer(1,7,12.5f,88.25f);q.poll(c);assertEquals(7,c.getPointerId());assertEquals(12.5f,c.getX(),.001f);assertEquals(88.25f,c.getY(),.001f);}@Test public void clear(){TouchCommandQueue q=new TouchCommandQueue(16);q.offer(1,1,0,0);q.clear();assertEquals(0,q.size());}@Test public void overflow(){TouchCommandQueue q=new TouchCommandQueue(16);for(int i=0;i<16;i++)q.offer(2,1,i,i);q.offer(3,1,99,99);TouchCommandQueue.Command c=new TouchCommandQueue.Command();q.poll(c);assertEquals(4,c.getType());q.poll(c);assertEquals(3,c.getType());}@Test public void empty(){assertFalse(new TouchCommandQueue(16).poll(new TouchCommandQueue.Command()));}}